import { useState, useEffect } from 'react';
import { conversationSteps } from '../data/script';

export const useConversation = () => {
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});

  const currentStep = conversationSteps[currentStepIndex];

  useEffect(() => {
    if (messages.length === 0) showNextSystemMessage(0);
  }, []);

  const showNextSystemMessage = (index) => {
    setIsTyping(true);
    setTimeout(() => {
      setMessages(prev => [...prev, { sender: 'bot', text: conversationSteps[index].message }]);
      setIsTyping(false);
    }, 1200);
  };

  const handleUserAnswer = (answer) => {
    // Record the time taken to answer (Clinical Insight: Psychomotor speed)
    const timestamp = new Date().toISOString();
    
    setMessages(prev => [...prev, { sender: 'user', text: Array.isArray(answer) ? answer.join(", ") : answer }]);
    
    if (currentStep.field) {
      setUserData(prev => ({ 
        ...prev, 
        [currentStep.field]: answer,
        [`${currentStep.field}_timestamp`]: timestamp 
      }));
    }

    const nextIndex = currentStepIndex + 1;
    if (nextIndex < conversationSteps.length) {
      setCurrentStepIndex(nextIndex);
      showNextSystemMessage(nextIndex);
    } else {
      setCurrentStepIndex(null); // Signal end of session
    }
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
